1	// 浏览器 CDP 端口发现 + 选择 - 单一职责模块
2	// 被 check-deps.mjs 和 cdp-proxy.mjs 共享。
3	//
4	// 选择规则（resolution）：
5	//   1. 调用方传入 override 参数（来自命令行 --browser） → 严格模式，找不到则硬错
6	//   2. config.env 里 WEB_ACCESS_BROWSER 设了 → 严格模式，找不到则硬错
7	//   3. 都没设 → "ask" 模式，提示调用方询问用户
8	//
9	// 不擅自降级：偏好不可用一律硬错，让用户介入。
10	// 持久态只有 config.env 一处；override 是单次 spawn 通过命令行参数表达，不读 process.env。
11	
12	import fs from 'node:fs';
13	import net from 'node:net';
14	import os from 'node:os';
15	import path from 'node:path';
16	import { fileURLToPath } from 'node:url';
17	
18	const SKILL_ROOT = path.resolve(path.dirname(fileURLToPath(import.meta.url)), '..');
19	const CONFIG_PATH = path.join(SKILL_ROOT, 'config.env');
20	
21	// 已知支持 chrome://inspect#remote-debugging toggle 的浏览器
22	// 加新浏览器：只改这里
23	export function knownBrowsers() {
24	  const home = os.homedir();
25	  const localAppData = process.env.LOCALAPPDATA || '';
26	  switch (os.platform()) {
27	    case 'darwin':
28	      return [
29	        { id: 'chrome',        label: 'Chrome',         devToolsPath: path.join(home, 'Library/Application Support/Google/Chrome/DevToolsActivePort') },
30	        { id: 'chrome-canary', label: 'Chrome Canary',  devToolsPath: path.join(home, 'Library/Application Support/Google/Chrome Canary/DevToolsActivePort') },
31	        { id: 'chromium',      label: 'Chromium',       devToolsPath: path.join(home, 'Library/Application Support/Chromium/DevToolsActivePort') },
32	        { id: 'edge',          label: 'Microsoft Edge', devToolsPath: path.join(home, 'Library/Application Support/Microsoft Edge/DevToolsActivePort') },
33	      ];
34	    case 'linux':
35	      return [
36	        { id: 'chrome',   label: 'Chrome',         devToolsPath: path.join(home, '.config/google-chrome/DevToolsActivePort') },
37	        { id: 'chromium', label: 'Chromium',       devToolsPath: path.join(home, '.config/chromium/DevToolsActivePort') },
38	        { id: 'edge',     label: 'Microsoft Edge', devToolsPath: path.join(home, '.config/microsoft-edge/DevToolsActivePort') },
39	      ];
40	    case 'win32':
41	      return [
42	        { id: 'chrome',   label: 'Chrome',         devToolsPath: path.join(localAppData, 'Google/Chrome/User Data/DevToolsActivePort') },
43	        { id: 'chromium', label: 'Chromium',       devToolsPath: path.join(localAppData, 'Chromium/User Data/DevToolsActivePort') },
44	        { id: 'edge',     label: 'Microsoft Edge', devToolsPath: path.join(localAppData, 'Microsoft/Edge/User Data/DevToolsActivePort') },
45	      ];
46	    default:
47	      return [];
48	  }
49	}
50	
51	// TCP 端口监听检测
52	// 用 TCP connect 而非 WebSocket，避免触发浏览器的远程调试授权弹窗。
53	export function checkPort(port, host = '127.0.0.1', timeoutMs = 2000) {
54	  return new Promise((resolve) => {
55	    const socket = net.createConnection(port, host);
56	    const timer = setTimeout(() => { socket.destroy(); resolve(false); }, timeoutMs);
57	    socket.once('connect', () => { clearTimeout(timer); socket.destroy(); resolve(true); });
58	    socket.once('error',   () => { clearTimeout(timer); resolve(false); });
59	  });
60	}
61	
62	// 读 config.env 文件（不写入 process.env，分清来源）
63	// 格式：KEY=VALUE，# 开头是注释
64	function readConfig() {
65	  const cfg = {};
66	  let content;
