1	#!/usr/bin/env node
2	// CDP Proxy - 通过 HTTP API 操控用户日常浏览器（Chrome / Edge / Chromium 等）
3	// 要求：浏览器已开启 remote debugging（chrome://inspect#remote-debugging toggle）
4	// Node.js 22+（使用原生 WebSocket）
5	
6	import http from 'node:http';
7	import { URL } from 'node:url';
8	import fs from 'node:fs';
9	import path from 'node:path';
10	import os from 'node:os';
11	import net from 'node:net';
12	import { selectBrowser, findFallbackPort } from './browser-discovery.mjs';
13	
14	// --- 解析命令行 --browser 参数（本次启动用哪个浏览器）---
15	function parseBrowserArg() {
16	  const argv = process.argv.slice(2);
17	  for (let i = 0; i < argv.length; i++) {
18	    if (argv[i] === '--browser' && argv[i + 1]) return argv[i + 1];
19	    if (argv[i].startsWith('--browser=')) return argv[i].slice('--browser='.length);
20	  }
21	  return null;
22	}
23	const BROWSER_OVERRIDE = parseBrowserArg();
24	
25	const PORT = parseInt(process.env.CDP_PROXY_PORT || '3456');
26	let ws = null;
27	let cmdId = 0;
28	const pending = new Map(); // id -> {resolve, timer}
29	const sessions = new Map(); // targetId -> sessionId
30	const managedTabs = new Map(); // targetId -> { lastAccessed: number }
31	const TAB_IDLE_TIMEOUT = parseInt(process.env.CDP_TAB_IDLE_TIMEOUT || '900000'); // 15 min default
32	const CLEANUP_INTERVAL = 60000; // sweep every 60s
33	
34	// --- WebSocket 兼容层 ---
35	let WS;
36	if (typeof globalThis.WebSocket !== 'undefined') {
37	  // Node 22+ 原生 WebSocket（浏览器兼容 API）
38	  WS = globalThis.WebSocket;
39	} else {
40	  // 回退到 ws 模块
41	  try {
42	    WS = (await import('ws')).default;
43	  } catch {
44	    console.error('[CDP Proxy] 错误：Node.js 版本 < 22 且未安装 ws 模块');
45	    console.error('  解决方案：升级到 Node.js 22+ 或执行 npm install -g ws');
46	    process.exit(1);
47	  }
48	}
49	
50	// proxy 启动时连接到的浏览器（用于 /health 暴露给 check-deps 比较）
51	let connectedBrowser = null; // { id, label, source }
52	
53	// pin 首次成功连接的浏览器 id。重连时只接受同一 id，避免悄悄降级到别的浏览器。
54	let pinnedBrowserId = null;
55	
56	// --- 自动发现浏览器调试端口 ---
57	// 决策完全委派给 browser-discovery.selectBrowser；此处只做日志和返回结构包装。
58	async function discoverChromePort() {
59	  const result = await selectBrowser(BROWSER_OVERRIDE);
60	  if (result.kind === 'ok') {
61	    if (pinnedBrowserId && pinnedBrowserId !== result.browser.id) {
62	      throw new Error(
63	        `本次连接的浏览器已经是 ${pinnedBrowserId}，不会自动切到 ${result.browser.id}。` +
64	        `如果想换成 ${result.browser.id}，请先在终端运行 pkill -f cdp-proxy.mjs 重置。`
65	      );
66	    }
67	    pinnedBrowserId = result.browser.id;
68	    connectedBrowser = { id: result.browser.id, label: result.browser.label, source: result.source };
69	    const tag = result.source === 'override' ? '[--browser 指定]' : '[config.env 偏好]';
70	    console.log(`[CDP Proxy] 选用 ${result.browser.label} (端口 ${result.browser.port}${result.browser.wsPath ? '，带 wsPath' : ''}) ${tag}`);
71	    return { port: result.browser.port, wsPath: result.browser.wsPath };
72	  }
73	  // mismatch：有显式偏好但未检测到 —— 硬错，绝不降级
74	  if (result.kind === 'mismatch') {
75	    const expected = result.override || result.configured;
76	    const src = result.source === 'override' ? '本次指定' : '默认偏好';
77	    throw new Error(
78	      `${src}的浏览器是 "${expected}"，但没连上。Agent 处理顺序：` +
79	      `(1) 先用系统命令打开 ${expected}（按平台选择，如 macOS 的 open -a），稍等后重试请求；` +
80	      `(2) 若仍失败，说明远程调试开关没启用 —— 告知用户在地址栏访问 ${expected}://inspect/#remote-debugging 勾选 "Allow remote debugging for this browser instance"。`
81	    );
82	  }
83	  // 已 pin 过浏览器（如首次连上 edge 后 edge 退出）：拒绝任何 fallback
84	  if (pinnedBrowserId) {
85	    throw new Error(
86	      `本次连接的浏览器是 ${pinnedBrowserId}，但现在没连上。Agent 处理顺序：` +
87	      `(1) 先用系统命令打开 ${pinnedBrowserId}（按平台选择），稍等后重试请求；` +
88	      `(2) 若仍失败，告知用户在地址栏访问 ${pinnedBrowserId}://inspect/#remote-debugging 重新勾选允许。` +
89	      `若想换成其他浏览器，请先在终端运行 pkill -f cdp-proxy.mjs 重置。`
90	    );
91	  }
92	  // 仅在「从未成功连接 + 无偏好/override」时允许固定端口兜底（手动 --remote-debugging-port 启动场景）
93	  const fallbackPort = await findFallbackPort();
94	  if (fallbackPort !== null) {
95	    connectedBrowser = { id: 'unknown', label: '未知（通过手动调试端口连接）', source: 'fallback' };
96	    console.log(`[CDP Proxy] 通过手动调试端口连接: ${fallbackPort}`);
97	    return { port: fallbackPort, wsPath: null };
98	  }
99	  return null;
100	}
101	
102	function getWebSocketUrl(port, wsPath) {
103	  if (wsPath) return `ws://127.0.0.1:${port}${wsPath}`;
104	  return `ws://127.0.0.1:${port}/devtools/browser`;
105	}
106	
107	// --- WebSocket 连接管理 ---
108	let chromePort = null;
109	let chromeWsPath = null;
110	
111	let connectingPromise = null;
112	async function connect() {
113	  if (ws && (ws.readyState === WS.OPEN || ws.readyState === 1)) return;
114	  if (connectingPromise) return connectingPromise;  // 复用进行中的连接
115	
116	  if (!chromePort) {
117	    const discovered = await discoverChromePort();
118	    if (!discovered) {
119	      throw new Error(
120	        'Chrome 未开启远程调试端口。请用以下方式启动 Chrome：\n' +
121	        '  macOS: /Applications/Google\\ Chrome.app/Contents/MacOS/Google\\ Chrome --remote-debugging-port=9222\n' +
122	        '  Linux: google-chrome --remote-debugging-port=9222\n' +
123	        '  或在 chrome://flags 中搜索 "remote debugging" 并启用'
124	      );
125	    }
126	    chromePort = discovered.port;
127	    chromeWsPath = discovered.wsPath;
128	  }
129	
130	  const wsUrl = getWebSocketUrl(chromePort, chromeWsPath);
131	  if (!wsUrl) throw new Error('无法获取 Chrome WebSocket URL');
132	
133	  return connectingPromise = new Promise((resolve, reject) => {
134	    ws = new WS(wsUrl);
135	
136	    const onOpen = () => {
137	      cleanup();
138	      connectingPromise = null;
139	      console.log(`[CDP Proxy] 已连接浏览器 (端口 ${chromePort})`);
140	      resolve();
141	    };
142	    const onError = (e) => {
143	      cleanup();
144	      connectingPromise = null;
145	      ws = null;
146	      chromePort = null;
147	      chromeWsPath = null;
148	      const msg = e.message || e.error?.message || '连接失败';
149	      console.error('[CDP Proxy] 连接错误:', msg, '（端口缓存已清除，下次将重新发现）');
150	      reject(new Error(msg));
151	    };
152	    const onClose = () => {
153	      console.log('[CDP Proxy] 连接断开');
154	      ws = null;
155	      chromePort = null; // 重置端口缓存，下次连接重新发现
156	      chromeWsPath = null;
157	      sessions.clear();
158	      managedTabs.clear();
159	    };
160	    const onMessage = (evt) => {
161	      const data = typeof evt === 'string' ? evt : (evt.data || evt);
162	      const msg = JSON.parse(typeof data === 'string' ? data : data.toString());
163	
164	      if (msg.method === 'Target.attachedToTarget') {
165	        const { sessionId, targetInfo } = msg.params;
166	        sessions.set(targetInfo.targetId, sessionId);
167	      }
168	      // 拦截页面对 Chrome 调试端口的探测请求（反风控）
169	      if (msg.method === 'Fetch.requestPaused') {
170	        const { requestId, sessionId: sid } = msg.params;
171	        sendCDP('Fetch.failRequest', { requestId, errorReason: 'ConnectionRefused' }, sid).catch(() => {});
172	      }
173	      if (msg.id && pending.has(msg.id)) {
174	        const { resolve, timer } = pending.get(msg.id);
175	        clearTimeout(timer);
176	        pending.delete(msg.id);
177	        resolve(msg);
178	      }
179	    };
180	
181	    function cleanup() {
182	      ws.removeEventListener?.('open', onOpen);
183	      ws.removeEventListener?.('error', onError);
184	    }
185	
186	    // 兼容 Node 原生 WebSocket 和 ws 模块的事件 API
187	    if (ws.on) {
188	      ws.on('open', onOpen);
189	      ws.on('error', onError);
190	      ws.on('close', onClose);
191	      ws.on('message', onMessage);
192	    } else {
193	      ws.addEventListener('open', onOpen);
194	      ws.addEventListener('error', onError);
195	      ws.addEventListener('close', onClose);
196	      ws.addEventListener('message', onMessage);
197	    }
198	  });
199	}
200	
201	function sendCDP(method, params = {}, sessionId = null) {
202	  return new Promise((resolve, reject) => {
203	    if (!ws || (ws.readyState !== WS.OPEN && ws.readyState !== 1)) {
204	      return reject(new Error('WebSocket 未连接'));
205	    }
206	    const id = ++cmdId;
207	    const msg = { id, method, params };
208	    if (sessionId) msg.sessionId = sessionId;
209	    const timer = setTimeout(() => {
210	      pending.delete(id);
211	      reject(new Error('CDP 命令超时: ' + method));
212	    }, 30000);
213	    pending.set(id, { resolve, timer });
214	    ws.send(JSON.stringify(msg));
215	  });
216	}
217	
218	// 已启用端口拦截的 session 集合（避免重复启用）
219	const portGuardedSessions = new Set();
220	
221	async function ensureSession(targetId) {
222	  if (sessions.has(targetId)) return sessions.get(targetId);
223	  const resp = await sendCDP('Target.attachToTarget', { targetId, flatten: true });
224	  if (resp.result?.sessionId) {
225	    const sid = resp.result.sessionId;
226	    sessions.set(targetId, sid);
227	    // 启用调试端口探测拦截
228	    await enablePortGuard(sid);
229	    return sid;
230	  }
231	  throw new Error('attach 失败: ' + JSON.stringify(resp.error));
232	}
