234	// 拦截页面对 Chrome 调试端口的探测（反风控）
235	// 只拦截 127.0.0.1:{chromePort} 的请求，不影响其他任何本地服务
236	async function enablePortGuard(sessionId) {
237	  if (!chromePort || portGuardedSessions.has(sessionId)) return;
238	  try {
239	    await sendCDP('Fetch.enable', {
240	      patterns: [
241	        { urlPattern: `http://127.0.0.1:${chromePort}/*`, requestStage: 'Request' },
242	        { urlPattern: `http://localhost:${chromePort}/*`, requestStage: 'Request' },
243	      ]
244	    }, sessionId);
245	    portGuardedSessions.add(sessionId);
246	  } catch { /* Fetch 域启用失败不影响主流程 */ }
247	}
