249	// --- 闲置 Tab 自动清理 ---
250	function touchTab(targetId) {
251	  const entry = managedTabs.get(targetId);
252	  if (entry) entry.lastAccessed = Date.now();
253	}
254	
255	async function cleanupIdleTabs() {
256	  if (!ws || (ws.readyState !== WS.OPEN && ws.readyState !== 1)) return;
257	  const now = Date.now();
258	  for (const [targetId, info] of managedTabs) {
259	    if (now - info.lastAccessed < TAB_IDLE_TIMEOUT) continue;
260	    try { await sendCDP('Target.closeTarget', { targetId }); } catch { /* tab may already be closed */ }
261	    sessions.delete(targetId);
262	    managedTabs.delete(targetId);
263	    console.log(`[CDP Proxy] Auto-closed idle tab: ${targetId}`);
264	  }
265	}
266	
267	async function closeAllManagedTabs() {
268	  if (!ws || (ws.readyState !== WS.OPEN && ws.readyState !== 1)) return;
269	  const targets = [...managedTabs.keys()];
270	  for (const targetId of targets) {
271	    try { await sendCDP('Target.closeTarget', { targetId }); } catch { /* ignore */ }
272	    sessions.delete(targetId);
273	    managedTabs.delete(targetId);
274	  }
275	  if (targets.length) console.log(`[CDP Proxy] Shutdown: closed ${targets.length} managed tab(s)`);
276	}
277	
278	// --- 等待页面加载 ---
279	async function waitForLoad(sessionId, timeoutMs = 15000) {
280	  // 启用 Page 域
281	  await sendCDP('Page.enable', {}, sessionId);
282	
283	  return new Promise((resolve) => {
284	    let resolved = false;
285	    const done = (result) => {
286	      if (resolved) return;
287	      resolved = true;
288	      clearTimeout(timer);
289	      clearInterval(checkInterval);
290	      resolve(result);
291	    };
292	
293	    const timer = setTimeout(() => done('timeout'), timeoutMs);
294	    const checkInterval = setInterval(async () => {
295	      try {
296	        const resp = await sendCDP('Runtime.evaluate', {
297	          expression: 'document.readyState',
298	          returnByValue: true,
299	        }, sessionId);
300	        if (resp.result?.result?.value === 'complete') {
301	          done('complete');
302	        }
303	      } catch { /* 忽略 */ }
304	    }, 500);
305	  });
306	}
