577	    // GET /info?target=xxx - 获取页面信息
578	    else if (pathname === '/info') {
579	      const sid = await ensureSession(q.target);
580	      const resp = await sendCDP('Runtime.evaluate', {
581	        expression: 'JSON.stringify({title: document.title, url: location.href, ready: document.readyState})',
582	        returnByValue: true,
583	      }, sid);
584	      res.end(resp.result?.result?.value || '{}');
585	    }
586	
587	    else {
588	      res.statusCode = 404;
589	      res.end(JSON.stringify({
590	        error: '未知端点',
591	        endpoints: {
592	          '/health': 'GET - 健康检查',
593	          '/targets': 'GET - 列出所有页面 tab',
594	          '/new': 'POST body=URL - 创建新后台 tab（自动等待加载）',
595	          '/close?target=': 'GET - 关闭 tab',
596	          '/navigate?target=': 'POST body=URL - 导航（自动等待加载）',
597	          '/back?target=': 'GET - 后退',
598	          '/info?target=': 'GET - 页面标题/URL/状态',
599	          '/eval?target=': 'POST body=JS表达式 - 执行 JS',
600	          '/click?target=': 'POST body=CSS选择器 - 点击元素',
601	          '/scroll?target=&y=&direction=': 'GET - 滚动页面',
602	          '/screenshot?target=&file=': 'GET - 截图',
603	        },
604	      }));
605	    }
606	  } catch (e) {
607	    res.statusCode = 500;
608	    res.end(JSON.stringify({ error: e.message }));
609	  }
610	});
