612	// 检查端口是否被占用
613	function checkPortAvailable(port) {
614	  return new Promise((resolve) => {
615	    const s = net.createServer();
616	    s.once('error', () => resolve(false));
617	    s.once('listening', () => { s.close(); resolve(true); });
618	    s.listen(port, '127.0.0.1');
619	  });
620	}
621	
622	async function main() {
623	  // 检查是否已有 proxy 在运行
624	  const available = await checkPortAvailable(PORT);
625	  if (!available) {
626	    // 验证已有实例是否健康
627	    try {
628	      const ok = await new Promise((resolve) => {
629	        http.get(`http://127.0.0.1:${PORT}/health`, { timeout: 2000 }, (res) => {
630	          let d = '';
631	          res.on('data', c => d += c);
632	          res.on('end', () => resolve(d.includes('"ok"')));
633	        }).on('error', () => resolve(false));
634	      });
635	      if (ok) {
636	        console.log(`[CDP Proxy] 已有实例运行在端口 ${PORT}，退出`);
637	        process.exit(0);
638	      }
639	    } catch { /* 端口占用但非 proxy，继续报错 */ }
640	    console.error(`[CDP Proxy] 端口 ${PORT} 已被占用`);
641	    process.exit(1);
642	  }
643	
644	  server.listen(PORT, '127.0.0.1', () => {
645	    console.log(`[CDP Proxy] 运行在 http://localhost:${PORT}`);
646	    // 启动时尝试连接 Chrome（非阻塞）
647	    connect().catch(e => console.error('[CDP Proxy] 初始连接失败:', e.message, '（将在首次请求时重试）'));
648	  });
649	
650	  // 定时清理闲置 tab
651	  const cleanupTimer = setInterval(cleanupIdleTabs, CLEANUP_INTERVAL);
652	  cleanupTimer.unref();
653	
654	  const shutdown = async (sig) => {
655	    console.log(`[CDP Proxy] ${sig}, cleaning up...`);
656	    clearInterval(cleanupTimer);
657	    await closeAllManagedTabs();
658	    process.exit(0);
659	  };
660	  process.on('SIGINT', () => shutdown('SIGINT'));
661	  process.on('SIGTERM', () => shutdown('SIGTERM'));
662	}
663	
664	// 防止未捕获异常导致进程崩溃
665	process.on('uncaughtException', (e) => {
666	  console.error('[CDP Proxy] 未捕获异常:', e.message);
667	});
668	process.on('unhandledRejection', (e) => {
669	  console.error('[CDP Proxy] 未处理拒绝:', e?.message || e);
670	});
671	
672	main();
